query:
-- 刪除所有與測試客戶相關的 assignments
DELETE FROM assignments 
WHERE demandId IN (
  SELECT d.id FROM demands d 
  JOIN clients c ON d.clientId = c.id 
  WHERE c.name LIKE '%測試%' OR c.name LIKE '%test%'
);

-- 刪除所有與測試員工相關的 assignments
DELETE FROM assignments 
WHERE workerId IN (
  SELECT id FROM workers 
  WHERE name LIKE '%測試%' OR name LIKE '%test%'
);

